    try:
        with open(WORKFLOW_FILE) as f:
            return json.load(f)
    except:
        return {"active": False}


def has_pending_work() -> bool:
    """检查是否有待处理的工作"""
    # 检查工作流
    workflow = get_workflow_status()
    if workflow.get("active"):
